-- Create "contacts" table
CREATE TABLE "contacts" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "owner_type" character varying NOT NULL,
  "owner_id" bigint NOT NULL,
  "name" character varying NOT NULL,
  "phone" character varying NULL,
  "mobile" character varying NULL,
  "email" character varying NULL,
  "title" character varying NULL,
  "is_primary" boolean NOT NULL DEFAULT false,
  "is_active" boolean NOT NULL DEFAULT true,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "contacts_owner_type_allowed" CHECK ((owner_type)::text = ANY ((ARRAY['CUSTOMER'::character varying, 'SUPPLIER'::character varying])::text[]))
);
-- Create index "contact_is_active" to table: "contacts"
CREATE INDEX "contact_is_active" ON "contacts" ("is_active");
-- Create index "contact_mobile" to table: "contacts"
CREATE INDEX "contact_mobile" ON "contacts" ("mobile");
-- Create index "contact_owner_type_owner_id" to table: "contacts"
CREATE INDEX "contact_owner_type_owner_id" ON "contacts" ("owner_type", "owner_id");
-- Create index "contact_owner_type_owner_id_is_primary" to table: "contacts"
CREATE UNIQUE INDEX "contact_owner_type_owner_id_is_primary" ON "contacts" ("owner_type", "owner_id", "is_primary") WHERE (is_primary = true);
-- Create index "contact_phone" to table: "contacts"
CREATE INDEX "contact_phone" ON "contacts" ("phone");
-- Create "suppliers" table
CREATE TABLE "suppliers" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "code" character varying NOT NULL,
  "name" character varying NOT NULL,
  "short_name" character varying NULL,
  "supplier_type" character varying NULL,
  "tax_no" character varying NULL,
  "is_active" boolean NOT NULL DEFAULT true,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "suppliers_supplier_type_allowed" CHECK ((supplier_type IS NULL) OR ((supplier_type)::text = ANY ((ARRAY['material'::character varying, 'outsourcing'::character varying, 'service'::character varying, 'mixed'::character varying])::text[])))
);
-- Create index "supplier_code" to table: "suppliers"
CREATE UNIQUE INDEX "supplier_code" ON "suppliers" ("code");
-- Create index "supplier_is_active" to table: "suppliers"
CREATE INDEX "supplier_is_active" ON "suppliers" ("is_active");
-- Create index "supplier_name" to table: "suppliers"
CREATE INDEX "supplier_name" ON "suppliers" ("name");
-- Create index "supplier_short_name" to table: "suppliers"
CREATE INDEX "supplier_short_name" ON "suppliers" ("short_name");
-- Create index "supplier_supplier_type" to table: "suppliers"
CREATE INDEX "supplier_supplier_type" ON "suppliers" ("supplier_type");
-- Create "customers" table
CREATE TABLE "customers" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "code" character varying NOT NULL,
  "name" character varying NOT NULL,
  "short_name" character varying NULL,
  "tax_no" character varying NULL,
  "is_active" boolean NOT NULL DEFAULT true,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "customer_code" to table: "customers"
CREATE UNIQUE INDEX "customer_code" ON "customers" ("code");
-- Create index "customer_is_active" to table: "customers"
CREATE INDEX "customer_is_active" ON "customers" ("is_active");
-- Create index "customer_name" to table: "customers"
CREATE INDEX "customer_name" ON "customers" ("name");
-- Create index "customer_short_name" to table: "customers"
CREATE INDEX "customer_short_name" ON "customers" ("short_name");
-- Create "sales_orders" table
CREATE TABLE "sales_orders" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "order_no" character varying NOT NULL,
  "customer_order_no" character varying NULL,
  "customer_snapshot" jsonb NULL,
  "order_date" timestamptz NOT NULL,
  "planned_delivery_date" timestamptz NULL,
  "lifecycle_status" character varying NOT NULL DEFAULT 'draft',
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "customer_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "sales_orders_customers_sales_orders" FOREIGN KEY ("customer_id") REFERENCES "customers" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "sales_orders_lifecycle_status_allowed" CHECK ((lifecycle_status)::text = ANY ((ARRAY['draft'::character varying, 'submitted'::character varying, 'active'::character varying, 'closed'::character varying, 'canceled'::character varying])::text[]))
);
-- Create index "salesorder_customer_id" to table: "sales_orders"
CREATE INDEX "salesorder_customer_id" ON "sales_orders" ("customer_id");
-- Create index "salesorder_customer_order_no" to table: "sales_orders"
CREATE INDEX "salesorder_customer_order_no" ON "sales_orders" ("customer_order_no");
-- Create index "salesorder_lifecycle_status" to table: "sales_orders"
CREATE INDEX "salesorder_lifecycle_status" ON "sales_orders" ("lifecycle_status");
-- Create index "salesorder_order_date" to table: "sales_orders"
CREATE INDEX "salesorder_order_date" ON "sales_orders" ("order_date");
-- Create index "salesorder_order_no" to table: "sales_orders"
CREATE UNIQUE INDEX "salesorder_order_no" ON "sales_orders" ("order_no");
-- Create index "salesorder_planned_delivery_date" to table: "sales_orders"
CREATE INDEX "salesorder_planned_delivery_date" ON "sales_orders" ("planned_delivery_date");
-- Create "sales_order_items" table
CREATE TABLE "sales_order_items" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "line_no" bigint NOT NULL,
  "product_code_snapshot" character varying NULL,
  "product_name_snapshot" character varying NULL,
  "color_snapshot" character varying NULL,
  "ordered_quantity" numeric(20,6) NOT NULL,
  "unit_price" numeric(20,6) NULL,
  "amount" numeric(20,6) NULL,
  "planned_delivery_date" timestamptz NULL,
  "line_status" character varying NOT NULL DEFAULT 'open',
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "sales_order_id" bigint NOT NULL,
  "product_id" bigint NOT NULL,
  "unit_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "sales_order_items_products_product" FOREIGN KEY ("product_id") REFERENCES "products" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "sales_order_items_sales_orders_items" FOREIGN KEY ("sales_order_id") REFERENCES "sales_orders" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "sales_order_items_units_unit" FOREIGN KEY ("unit_id") REFERENCES "units" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "sales_order_items_amount_non_negative" CHECK ((amount IS NULL) OR (amount >= (0)::numeric)),
  CONSTRAINT "sales_order_items_line_no_positive" CHECK (line_no > 0),
  CONSTRAINT "sales_order_items_line_status_allowed" CHECK ((line_status)::text = ANY ((ARRAY['open'::character varying, 'closed'::character varying, 'canceled'::character varying])::text[])),
  CONSTRAINT "sales_order_items_ordered_qty_positive" CHECK (ordered_quantity > (0)::numeric),
  CONSTRAINT "sales_order_items_unit_price_non_negative" CHECK ((unit_price IS NULL) OR (unit_price >= (0)::numeric))
);
-- Create index "salesorderitem_line_status" to table: "sales_order_items"
CREATE INDEX "salesorderitem_line_status" ON "sales_order_items" ("line_status");
-- Create index "salesorderitem_planned_delivery_date" to table: "sales_order_items"
CREATE INDEX "salesorderitem_planned_delivery_date" ON "sales_order_items" ("planned_delivery_date");
-- Create index "salesorderitem_product_id" to table: "sales_order_items"
CREATE INDEX "salesorderitem_product_id" ON "sales_order_items" ("product_id");
-- Create index "salesorderitem_sales_order_id_line_no" to table: "sales_order_items"
CREATE UNIQUE INDEX "salesorderitem_sales_order_id_line_no" ON "sales_order_items" ("sales_order_id", "line_no");
-- Create index "salesorderitem_unit_id" to table: "sales_order_items"
CREATE INDEX "salesorderitem_unit_id" ON "sales_order_items" ("unit_id");
